import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate, useLocation } from 'react-router-dom';
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';
import SideNav from './Components/SideNav';
import ChatBox from './Components/ChatBox';
import HomePage from './Components/HomePage';
import Settings from './Components/Settings';
import ImportDataSidebar from './Components/ImportDataSidebar';

function AppContent() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [domain, setDomain] = useState('');
  const [project, setProject] = useState('');
  const [issueType, setIssueType] = useState('');
  const [jiraData, setJiraData] = useState([]);
  const [isSidebarVisible, setIsSidebarVisible] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();

  // Handle login success
  const login = () => {
    setIsAuthenticated(true);
  };

  // Handle logout (navigate to login page)
  const logout = () => {
    setIsAuthenticated(false);
    navigate('/Login');
  };

  // Function to fetch Jira data
  const handleFetchData = async (domain, project, issueType) => {
    try {
      const response = await fetch(
        `https://localhost:7216/api/Details?domain=${domain}&project=${project}&issueType=${issueType}`,
        {
          method: 'GET',
        }
      );
      if (response.ok) {
        const data = await response.json();
        setJiraData(data);  // Set the fetched Jira data
      } else {
        alert('Error fetching data');
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  useEffect(() => {
    // Fetch data if domain, project, or issueType are already set (initial fetch)
    if (domain && project && issueType) {
      handleFetchData(domain, project, issueType);
    }
  }, [domain, project, issueType]); // Trigger re-fetching when these settings change

  return (
    <div className="App">
      <h1>J-Test</h1>

      {isAuthenticated && <SideNav logout={logout} />}

      <Routes>
        <Route path="/Login" element={<LoginPage login={login} />} />
        <Route path="/Signup" element={<SignupPage />} />
        <Route path="/HomePage" element={isAuthenticated ? <HomePage /> : <Navigate to="/Login" />} />
        <Route path="/ChatBox" element={
          isAuthenticated ? (
            <ChatBox 
              jiraData={jiraData} 
              domain={domain} 
              project={project} 
              issueType={issueType} 
              handleFetchData={handleFetchData} // Pass the fetch function to ChatBox
            />
          ) : <Navigate to="/Login" />
        } />
        <Route path="/Settings" element={isAuthenticated ? (
          <Settings
          setDomain={setDomain}
          setProject={setProject}
          setIssueType={setIssueType}
        />        
        ) : <Navigate to="/Login" /> }
        />
        <Route path="/" element={<Navigate to="/Login" />} />
      </Routes>

      {/* Conditionally render the "Import Data" button only when on ChatBox route */}
      {location.pathname === '/ChatBox' && (
        <button className="import-btn" onClick={() => { setIsSidebarVisible(true); handleFetchData(domain, project, issueType); }} disabled={false}>
          &#x2192; {/* Right arrow symbol */}
        </button>
      )}

      {/* Sidebar for importing Jira data */}
      {isSidebarVisible && (
        <ImportDataSidebar
          jiraData={jiraData}
          onSelectUserStory={(story) => console.log('Selected story:', story)}
          onClose={() => setIsSidebarVisible(false)}
          isSidebarVisible={isSidebarVisible}
        />
      )}
    </div>
  );
}

function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}

export default App;
